function slug(text: string) {
  return text
    .replace(/\s+/g, "-")
    .replace(/[^\w\u0600-\u06FF-]/g, "")
    .toLowerCase()
    .slice(0, 60) + "-" + Math.random().toString(36).slice(2, 6);
}

