async function seedGroup1() {
  console.log("🌱 المجموعة الأولى: التصنيفات + الدروس (1-15)\n");

  // Clear everything
  console.log("🗑️  حذف البيانات القديمة...");
  await db.delete(fatawaAudio);
  await db.delete(audioFiles);
  await db.delete(comments);
  await db.delete(fatawa);
  await db.delete(fatawaCategories);
  await db.delete(posts);
  await db.delete(categories);
  await db.delete(users);
  console.log("   ✅ تم حذف جميع البيانات\n");

  // Admin
  console.log("👤 إنشاء حساب المدير...");
  const hashed = await bcrypt.hash(process.env.ADMIN_PASSWORD!, 12);
  await db.insert(users).values({ email: process.env.ADMIN_EMAIL!, password: hashed });
  console.log("   ✅ تم\n");

  // Lesson categories
  console.log("🗂️  تصنيفات الدروس...");
  for (const cat of lessonCategoriesData) {
    await db.insert(categories).values(cat);
    console.log(`   ✅ ${cat.name}`);
  }

  // Posts group 1
  console.log("\n📝 الدروس (1-15)...");
  const allCats = await db.select().from(categories);
  const catMap: Record<string, number> = {};
  for (const c of allCats) catMap[c.slug] = c.id;

  for (const post of postsGroup1) {
    const categoryId = catMap[post.categorySlug];
    await db.insert(posts).values({
      title: post.title,
      slug: slug(post.title),
      content: post.content,
      excerpt: post.excerpt,
      categoryId,
      status: "published",
    });
    console.log(`   ✅ ${post.title.substring(0, 50)}...`);
  }

  console.log(`\n✅ المجموعة الأولى اكتملت! (${postsGroup1.length} درس)`);
  console.log("👉 الآن شغّل: npx tsx lib/seed.ts للمجموعة التالية");
  process.exit(0);
}
