async function seedGroup3() {
  console.log("🌱 المجموعة الثالثة: الدروس (31-40)\n");

  const allCats = await db.select().from(categories);
  const catMap: Record<string, number> = {};
  for (const c of allCats) catMap[c.slug] = c.id;

  console.log("📝 إضافة الدروس...");
  let count = 0;
  for (const post of postsGroup3) {
    const categoryId = catMap[post.categorySlug];
    if (!categoryId) {
      console.log(`   ⚠️ تصنيف غير موجود: ${post.categorySlug}`);
      continue;
    }
    await db.insert(posts).values({
      title: post.title,
      slug: slug(post.title),
      content: post.content,
      excerpt: post.excerpt,
      categoryId,
      status: "published",
    });
    console.log(`   ✅ ${post.title.substring(0, 50)}...`);
    count++;
  }

  console.log(`\n✅ المجموعة الثالثة اكتملت! (${count} درس)`);
  console.log("👉 الآن شغّل: npx tsx lib/seed.ts للمجموعة التالية");
  process.exit(0);
}

