async function seedGroup4() {
  console.log("🌱 المجموعة الرابعة: 60 تعليقاً\n");

  const allPosts = await db.select().from(posts);
  if (allPosts.length === 0) {
    console.log("⚠️ لا توجد دروس لإضافة تعليقات عليها.");
    process.exit(1);
  }

  console.log("📝 إضافة التعليقات...");
  for (let i = 0; i < 60; i++) {
    const post = allPosts[Math.floor(Math.random() * allPosts.length)];
    const text = commentTexts[Math.floor(Math.random() * commentTexts.length)];
    const name = commentNames[Math.floor(Math.random() * commentNames.length)];

    await db.insert(comments).values({
      postId: post.id,
      authorName: name,
      content: text,
      status: "approved",
    });
  }

  console.log(`\n✅ المجموعة الرابعة اكتملت! (60 تعليق)`);
  console.log("👉 الآن شغّل: npx tsx lib/seed.ts للمجموعة التالية");
  process.exit(0);
}

